*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --ink:    #050505;
  --paper:  #FCFCFC;
  --white:  #FFFFFF;
  --purple: #9741F4;
  --orange: #FF820D;
  --muted:  #B1B6C1;
  --line:   #E8E8E8;
  --max-w:  1200px;
  --pad-x:  clamp(1.25rem, 5vw, 2.5rem);
  --sec:    clamp(2rem, 4vw, 4rem);
  --ease-out: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
}

html { scroll-behavior: smooth; scroll-padding-top: 80px; overflow-x: clip; }
body { max-width: 100%; overflow-x: clip; }
body {
  font-family: 'Manrope', sans-serif;
  font-weight: 400;
  font-size: 1rem;
  line-height: 1.65;
  background: var(--paper);
  color: var(--ink);
  -webkit-font-smoothing: antialiased;
}

.container { max-width: var(--max-w); margin: 0 auto; padding: 0 var(--pad-x); }
section { padding: var(--sec) 0; }
.dark  { background: var(--ink); }
.white { background: var(--white); }

h1 { font-size: clamp(2.8rem, 7vw, 5.5rem); font-weight: 300; line-height: 1.05; letter-spacing: -0.025em; }
h2 { font-size: clamp(1.9rem, 4vw, 2.8rem); font-weight: 300; line-height: 1.1;  letter-spacing: -0.02em; }
h3 { font-size: clamp(1.2rem, 2vw, 1.5rem);  font-weight: 300; line-height: 1.2; letter-spacing: -0.01em; }
h4 { font-size: 1rem; font-weight: 700; line-height: 1.3; }
p  { line-height: 1.7; }

.eyebrow {
  display: block;
  font-size: 0.68rem; font-weight: 700;
  letter-spacing: 0.18em; text-transform: uppercase;
  color: var(--orange); margin-bottom: 0.9rem;
}
.divider       { display: block; width: 48px; height: 1.5px; background: var(--purple); margin: 1.25rem auto; }
.divider--left { margin: 1.25rem 0; }

.sec-head { text-align: center; max-width: 720px; margin: 0 auto 2.5rem; }
.sec-head h2 { margin-bottom: 0.6rem; }
.sec-sub  { color: var(--muted); font-weight: 300; font-size: 0.975rem; margin-top: 0.5rem; }

/* ── FOUNDER ROTATING IMAGES ──────────────── */
.founders-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 4rem; align-items: center; }
.founders-img-stack { position: relative; border-radius: 8px; overflow: hidden; aspect-ratio: 3/4; background: #f0f0f0; }
.founders-img-slide { position: absolute; inset: 0; opacity: 0; transition: opacity 0.8s ease; }
.founders-img-slide.active { opacity: 1; }
.founders-img-slide img { width: 100%; height: 100%; object-fit: cover; display: block; }
.founder-caption {
  position: absolute; bottom: 0; left: 0; right: 0;
  background: linear-gradient(to top, rgba(5,5,5,0.75) 0%, transparent 100%);
  padding: 2rem 1.25rem 1.1rem;
}
.founder-name { display: block; font-size: 1rem; font-weight: 700; color: #fff; letter-spacing: -0.01em; }
.founder-role { display: block; font-size: 0.78rem; font-weight: 400; color: rgba(255,255,255,0.65); margin-top: 0.15rem; letter-spacing: 0.03em; }
.founders-img-dots { position: absolute; bottom: 1rem; left: 50%; transform: translateX(-50%); display: flex; gap: 0.5rem; z-index: 2; }
.fimg-dot { width: 6px; height: 6px; border-radius: 50%; background: rgba(255,255,255,0.45); cursor: pointer; transition: background 0.2s, width 0.3s cubic-bezier(0.16,1,0.3,1); }
.fimg-dot.active { background: #fff; width: 18px; border-radius: 3px; }

/* ── THREE IMAGE STRIP ─────────────────────── */
.img-strip-grid { display: grid; grid-template-columns: repeat(3,1fr); }
.img-strip-item { position: relative; overflow: hidden; aspect-ratio: 4/3; cursor: pointer; }
.img-strip-item img { width: 100%; height: 100%; object-fit: cover; display: block; transition: transform 0.65s cubic-bezier(0.16,1,0.3,1); filter: brightness(0.75); }
.img-strip-item:hover img { transform: scale(1.04); filter: brightness(0.9); }
.img-strip-label { position: absolute; bottom: 1.25rem; left: 1.25rem; color: rgba(255,255,255,0.8); font-size: 0.78rem; font-weight: 700; letter-spacing: 0.1em; text-transform: uppercase; visibility: hidden; }

/* ── OUTCOMES IMAGE LEFT ───────────────────── */
.outcomes-img-wrap { border-radius: 8px; overflow: hidden; height: 100%; min-height: 360px; }
@media (max-width: 768px) { .outcomes-img-wrap { min-height: 220px; } }
.outcomes-img-wrap img { width: 100%; height: 100%; object-fit: cover; display: block; }

/* ── PARTNER CARD ALIGNMENT ────────────────── */
.partner-body { padding: 1.75rem; display: flex; flex-direction: column; height: 100%; }
.partner-body-top { flex: 1; }
.partner-body-top .p-icon { margin-bottom: 1rem; }

